function detectProvinceFromText(text) {
  const t = String(text || '').toLowerCase().normalize('NFD').replace(/\p{M}/gu, '');
  const aliases = {
    tp_ho_chi_minh: ['tp hcm', 'hcm', 'ho chi minh', 'tphcm', 'sai gon'],
    dong_nai: ['dong nai', 'bien hoa'],
    binh_duong: ['binh duong', 'thu dau mot'],
    ba_ria_vung_tau: ['vung tau', 'ba ria'],
    tp_can_tho: ['can tho'],
  };
  for (const [code, list] of Object.entries(aliases)) {
    for (const a of list) {
      if (t.includes(a.normalize('NFD').replace(/\p{M}/gu, ''))) return code;
    }
  }
  return null;
}


const LEGAL_PACK_READY_STATUSES = new Set(['active', 'ready', 'verified']);

function validateLegalPack(pack) {
  const errors = [];

  if (!pack || typeof pack !== 'object' || Array.isArray(pack)) {
    return {
      valid: false,
      status: 'blocked',
      errors: ['MISSING_LEGAL_PACK'],
      fact_count: 0,
    };
  }

  if (pack.needs_human_legal_source === true) {
    errors.push('NEEDS_HUMAN_LEGAL_SOURCE');
  } else if (pack.needs_human_legal_source !== false) {
    errors.push('MISSING_NEEDS_HUMAN_STATUS');
  }

  if (
    pack.status != null
    && !LEGAL_PACK_READY_STATUSES.has(String(pack.status).trim().toLowerCase())
  ) {
    errors.push('LEGAL_PACK_STATUS_NOT_READY');
  }

  const facts = Array.isArray(pack.facts) ? pack.facts : [];
  if (facts.length === 0) {
    errors.push('EMPTY_LEGAL_FACTS');
  }

  const seenClaimIds = new Set();
  for (const fact of facts) {
    const claimId = String(fact?.claim_id || '').trim();
    if (!claimId) {
      errors.push('FACT_MISSING_CLAIM_ID');
    } else if (seenClaimIds.has(claimId)) {
      errors.push('DUPLICATE_CLAIM_ID');
    } else {
      seenClaimIds.add(claimId);
    }

    const refs = Array.isArray(fact?.source_refs)
      ? fact.source_refs.map((ref) => String(ref || '').trim()).filter(Boolean)
      : [];
    if (refs.length === 0) errors.push('FACT_MISSING_SOURCE_REFS');
  }

  const forbidden = Array.isArray(pack.forbidden_claims)
    ? pack.forbidden_claims.map((claim) => String(claim || '').trim()).filter(Boolean)
    : [];
  if (forbidden.length === 0) errors.push('MISSING_FORBIDDEN_CLAIMS');

  if (pack.disclaimer_required !== true) {
    errors.push('DISCLAIMER_REQUIRED_NOT_TRUE');
  }

  const uniqueErrors = [...new Set(errors)];
  return {
    valid: uniqueErrors.length === 0,
    status: uniqueErrors.length === 0 ? 'ready' : 'blocked',
    errors: uniqueErrors,
    fact_count: facts.length,
    claim_ids: [...seenClaimIds],
    source_ref_count: facts.reduce(
      (count, fact) => count + (
        Array.isArray(fact?.source_refs)
          ? fact.source_refs.map((ref) => String(ref || '').trim()).filter(Boolean).length
          : 0
      ),
      0,
    ),
  };
}


const MIN_SCORE = 70;
const BATCH = 3;
const FORMAT_ROUTING = {"version":1,"agent3_text_post_formats":["fb_page_post","fb_page_post_image","facebook_page","facebook","website_article","blog_seo","aio_seo"],"agent6_video_formats":["fb_reels","tiktok","youtube_shorts","short_video_package"],"carousel_formats":["carousel_image"],"format_type_by_product":{"fb_reels":"video_script","tiktok":"video_script","youtube_shorts":"video_script","short_video_package":"video_script","fb_page_post_image":"text_post","fb_page_post":"text_post","facebook_page":"text_post","carousel_image":"carousel","website_article":"text_post","blog_seo":"text_post"},"prompt_hints":{"text_post":"Bài đọc Facebook Page: hook_line ≤25 từ + body Q&A (H2/H3 là câu hỏi). KHÔNG viết script theo giây.","video_script":"Chỉ Agent 6 — hook visual/verbal + body_beats theo giây. KHÔNG dùng cho Agent 3.","carousel":"Chia slide (Slide 1…N), mỗi slide 1 ý. KHÔNG viết bài đọc dài một khối."}};

const ALLOW_SEGMENTS = new Set([
  'noxh_income', 'valuation', 'sme_credit', 'general_inbound',
]);

const VIDEO_FORMATS = new Set([
  ...(FORMAT_ROUTING.agent6_video_formats || []),
  'tiktok', 'tt', 'fb', 'fb_page', 'fb_group', 'fb_reels', 'reels', 'instagram', 'youtube_shorts', 'shorts',
]);

function parseMeta(raw) {
  if (!raw) return {};
  try {
    return typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch {
    return {};
  }
}

function normPlatform(raw) {
  const key = String(raw || 'tiktok').trim().toLowerCase();
  const map = {
    tt: 'tiktok',
    fb: 'fb_reels',
    fb_group: 'fb_reels',
    reels: 'fb_reels',
    page: 'fb_page',
    shorts: 'youtube_shorts',
    yt_shorts: 'youtube_shorts',
  };
  return map[key] || key;
}

function resolveFormat(meta, row) {
  return String(
    meta.content_format
    || meta.product_type
    || row.product_type
    || meta.editorial_brief_v1?.content_format
    || row.platform
    || 'fb_reels',
  ).trim().toLowerCase();
}

function editorialPriority(meta) {
  const scheduled = meta.scheduled_publish_at || meta.editorial_brief_v1?.scheduled_publish_at;
  if (scheduled) {
    const t = new Date(scheduled).getTime();
    if (!Number.isNaN(t)) return t;
  }
  const calId = String(meta.editorial_calendar_id || '').trim();
  if (calId) {
    const num = Number(calId.split(':').pop());
    if (Number.isFinite(num)) return num;
  }
  return 999999;
}

const res = $input.first().json;
const rows = Array.isArray(res.values) ? res.values : [];
if (rows.length < 2) {
  return [{ json: { empty: true, message: 'content_queue trống' } }];
}

const headers = rows[0].map((x) => String(x ?? '').trim().toLowerCase());
const pool = [];
const blockers = { no_brief: 0, already_draft: 0, bad_segment: 0, low_score: 0, not_classified: 0, bad_format: 0, short_text: 0 };

for (let i = 1; i < rows.length; i++) {
  const cells = rows[i];
  if (!cells?.some((c) => String(c ?? '').trim())) continue;

  const row = { sheet_row: i + 1 };
  headers.forEach((key, j) => {
    if (key) row[key] = cells[j] ?? '';
  });

  const segment = String(row.segment || '').trim().toLowerCase();
  const score = Number(row.score || 0);
  const status = String(row.status || '').trim().toLowerCase();
  const meta = parseMeta(row.meta);
  const fmt = resolveFormat(meta, row);
  const platformRaw = String(row.platform || fmt || 'tiktok').trim().toLowerCase();

  if (meta.video_draft_created === true) { blockers.already_draft += 1; continue; }
  if (!ALLOW_SEGMENTS.has(segment)) { blockers.bad_segment += 1; continue; }
  if (score < MIN_SCORE) { blockers.low_score += 1; continue; }
  if (status !== 'classified' && row.claude_verdict !== 'qualified') { blockers.not_classified += 1; continue; }

  const isVideoFormat = VIDEO_FORMATS.has(fmt) || VIDEO_FORMATS.has(platformRaw) || VIDEO_FORMATS.has(normPlatform(platformRaw));
  if (!isVideoFormat) { blockers.bad_format += 1; continue; }

  const text = String(row.text || '').trim();
  if (text.length < 20) { blockers.short_text += 1; continue; }

  if (!meta.editorial_brief_v1) { blockers.no_brief += 1; continue; }

  const LEGAL_SEGMENTS = new Set(['noxh_income', 'valuation', 'sme_credit']);
  if (LEGAL_SEGMENTS.has(segment)) {
    const pack = meta.legal_retrieval_pack;
    const legalValidation = validateLegalPack(pack);
    if (!legalValidation.valid) {
      blockers.no_legal_pack = (blockers.no_legal_pack || 0) + 1;
      continue;
    }
    row.legal_retrieval_pack = pack;
    row.legal_pack_validation = legalValidation;
  }

  const ensured = ensureIntakeV1(
    { ...row, segment, score, intake_stub_source: 'agent6_filter' },
    meta
  );

  row.target_platform = normPlatform(platformRaw === fmt ? platformRaw : fmt);
  if (row.target_platform === 'fb_page' || row.target_platform === 'fb_group') {
    row.target_platform = 'fb_reels';
  }

  row.meta_parsed = ensured.meta;
  row.intake_v1 = ensured.intake_v1;
  row.intake_stubbed = ensured.stubbed;
  row.editorial_brief_v1 = meta.editorial_brief_v1;
  row.format_type = 'video_script';
  row.editorial_priority = editorialPriority(meta);
  pool.push(row);
}

pool.sort((a, b) => a.editorial_priority - b.editorial_priority);
const out = pool.slice(0, BATCH).map((row) => ({ json: row }));

if (!out.length) {
  return [{
    json: {
      empty: true,
      message: 'Không còn candidate video — cần format video + editorial_brief_v1 + classified score≥70',
      blockers,
    },
  }];
}

return out;

